// Generate partition creation SQL for next 3 months
const input = $input.first().json;
const currentYear = input.current_year;
const currentMonth = input.current_month;

const partitions = [];

for (let i = 0; i < 3; i++) {
  let targetMonth = currentMonth + i;
  let targetYear = currentYear;

  // Handle year rollover
  while (targetMonth > 12) {
    targetMonth -= 12;
    targetYear += 1;
  }

  // Calculate next month for end date
  let nextMonth = targetMonth + 1;
  let nextYear = targetYear;
  if (nextMonth > 12) {
    nextMonth = 1;
    nextYear += 1;
  }

  const monthPadded = String(targetMonth).padStart(2, '0');
  const nextMonthPadded = String(nextMonth).padStart(2, '0');

  partitions.push({
    partition_name: `chat_query_logs_${targetYear}_${monthPadded}`,
    start_date: `${targetYear}-${monthPadded}-01`,
    end_date: `${nextYear}-${nextMonthPadded}-01`,
    year: targetYear,
    month: targetMonth
  });
}

return partitions.map(p => ({ json: p }));

